mapper.select:


    1=1
    and DJXH = #{req.djxh}
    and SHXYDM = #{req.shxydm}
    and SHXYDM = #{req.nsrsbh}
    and NSRJC = #{req.nsrjc}
    and (DWDM = #{req.deptId} or DEPT_ID = #{req.deptId})
    and GHJGXZJB = #{req.ghjgxzjb}
    and CLGHBJ = #{req.clghbj}
    and HYGHBZ = #{req.hyghbz}
    and SDGHJGXZJB = #{req.sdghjgxzjb}
    and ZGSWJ_DM = #{req.zgswjDm}
    and ZGSWSKFJ_DM = #{req.zgswskfjDm}
    and SSGLY_DM = #{req.ssglyDm}
    and GHLB_DM = #{req.ghlbDm}
    and XTLB_DM = #{req.xtlbDm}
    and ZZJGLX_DM = #{req.zzjglxDm}
    and HY_DM = #{req.hyDm}
    and DJZCLX_DM = #{req.djzclxDm}
    and DWLSGX_DM = #{req.dwlsgxDm}
    and SBLB_DM = #{req.sblbDm}
    and SKSSQQ >= #{req.skssqq}
    and SKSSQZ <= #{req.skssqz}
    and ZSPM_DM = #{req.zspmDm}
    and JSBJ = #{req.jsbj}
    and CBJTHBJ = #{req.cbjthbj}
    and XWLX = #{req.xwlx}
    and RKRQ between #{req.beginRkrq} and #{req.endRkrq}
    and JSRQ between #{req.beginJsrq} and #{req.endJsrq}

GROUP BY
T.DWDM,T.DEPT_ID
